// Service Report Work Times Calendar v7
// Simplified - only current user's times
(function() {
    var currentEmployee = null;
    var calendarContainer = null;
    var calendarEl = null;
    var showWeekends = true;
    var currentMinTime = '06:00:00';
    var currentMaxTime = '22:00:00';

    var container = root_element.querySelector('.sr-calendar-container');
    if (!container) return;

    var calendarPlaceholder = root_element.querySelector('#work-times-calendar');
    var startDateInput = root_element.querySelector('#filter-start-date');
    var endDateInput = root_element.querySelector('#filter-end-date');
    var weekendToggleBtn = root_element.querySelector('#btn-toggle-weekends');

    var instanceId = 'sr-cal-' + Math.random().toString(36).substr(2, 9);

    function getCustomerColor(customerName) {
        if (!customerName || customerName === '') return 'hsl(200, 70%, 45%)';
        var hash = 0;
        for (var i = 0; i < customerName.length; i++) {
            hash = customerName.charCodeAt(i) + ((hash << 5) - hash);
        }
        var hue = Math.abs(hash % 360);
        return 'hsl(' + hue + ', 65%, 45%)';
    }

    async function init() {
        await loadDependencies();
        createExternalCalendarContainer();
        await getCurrentEmployee();
        setInitialFilters();
        initCalendar();
        setupEventListeners();
        setupResizeObserver();
    }

    async function loadDependencies() {
        if (!document.querySelector('link[href*="fullcalendar"]')) {
            var link = document.createElement('link');
            link.rel = 'stylesheet';
            link.href = '/assets/frappe/js/lib/fullcalendar/fullcalendar.min.css';
            document.head.appendChild(link);
        }
        await new Promise(function(resolve) { setTimeout(resolve, 100); });
        if (typeof $.fn.fullCalendar === 'undefined') {
            await frappe.require(['/assets/frappe/js/lib/fullcalendar/fullcalendar.min.js']);
        }
    }

    function createExternalCalendarContainer() {
        calendarContainer = document.createElement('div');
        calendarContainer.id = instanceId;
        calendarContainer.style.cssText = 'position:absolute;z-index:10;background:var(--card-bg);';
        document.body.appendChild(calendarContainer);
        calendarEl = document.createElement('div');
        calendarEl.id = instanceId + '-cal';
        calendarContainer.appendChild(calendarEl);

        // Inject styles
        var styleId = instanceId + '-styles';
        if (!document.getElementById(styleId)) {
            var style = document.createElement('style');
            style.id = styleId;
            style.textContent =
                '#' + instanceId + ' .fc-bgevent.core-hours { background-color: rgba(0, 0, 0, 0.08) !important; }' +
                '#' + instanceId + ' .fc-nonbusiness { background-color: transparent !important; }' +
                '#' + instanceId + ' .fc-sun, #' + instanceId + ' .fc-sat { background-color: transparent !important; }' +
                '#' + instanceId + ' .fc-time-grid .fc-slats tr { height: 10px !important; }' +
                '#' + instanceId + ' .fc-time-grid .fc-slats td { height: 10px !important; max-height: 10px !important; }' +
                '#' + instanceId + ' .fc-time-grid .fc-slats .fc-minor td { height: 10px !important; }' +
                '#' + instanceId + ' .fc-axis { font-size: 11px !important; padding: 0 4px !important; }' +
                '#' + instanceId + ' .fc-toolbar .fc-left { min-width: 200px; }' +
                '#' + instanceId + ' .fc-toolbar .fc-button { padding: 6px 12px !important; min-width: 36px; display: inline-flex !important; align-items: center !important; justify-content: center !important; line-height: 1 !important; }' +
                '#' + instanceId + ' .fc-toolbar .fc-prev-button, #' + instanceId + ' .fc-toolbar .fc-next-button { min-width: 40px; }';
            document.head.appendChild(style);
        }

        positionCalendarContainer();
    }

    function positionCalendarContainer() {
        if (!calendarPlaceholder || !calendarContainer) return;
        var rect = calendarPlaceholder.getBoundingClientRect();
        var scrollTop = window.pageYOffset || document.documentElement.scrollTop;
        var scrollLeft = window.pageXOffset || document.documentElement.scrollLeft;
        calendarContainer.style.top = (rect.top + scrollTop) + 'px';
        calendarContainer.style.left = (rect.left + scrollLeft) + 'px';
        calendarContainer.style.width = rect.width + 'px';
        calendarContainer.style.minHeight = '650px';
    }

    function setupResizeObserver() {
        window.addEventListener('scroll', positionCalendarContainer);
        window.addEventListener('resize', function() {
            positionCalendarContainer();
            if (calendarEl) $(calendarEl).fullCalendar('render');
        });
        setInterval(positionCalendarContainer, 1000);
        $(document).on('page-change', cleanup);
    }

    function cleanup() {
        if (calendarContainer && calendarContainer.parentNode) {
            calendarContainer.parentNode.removeChild(calendarContainer);
        }
    }

    async function getCurrentEmployee() {
        try {
            var response = await frappe.call({
                method: 'fieldservice.api.get_current_employee',
                async: true
            });
            currentEmployee = response.message;
        } catch (error) {
            console.error('Fehler:', error);
        }
    }

    function toggleWeekends() {
        showWeekends = !showWeekends;
        if (calendarEl) {
            $(calendarEl).fullCalendar('option', 'weekends', showWeekends);
        }
        updateWeekendButtonText();
    }

    function updateWeekendButtonText() {
        if (weekendToggleBtn) {
            weekendToggleBtn.textContent = showWeekends ? 'Nur Werktage' : 'Ganze Woche';
        }
    }

    function calculateTimeRange(events) {
        if (!events || events.length === 0) {
            return { minTime: '06:00:00', maxTime: '22:00:00' };
        }

        var minHour = 24;
        var maxHour = 0;

        events.forEach(function(event) {
            var startMoment = moment(event.start);
            var endMoment = moment(event.end);

            var startHour = startMoment.hours();
            var endHour = endMoment.hours();
            var endMinute = endMoment.minutes();

            if (endMinute > 0) {
                endHour = endHour + 1;
            }

            if (startHour < minHour) minHour = startHour;
            if (endHour > maxHour) maxHour = endHour;
        });

        minHour = Math.max(0, minHour - 1);
        maxHour = Math.min(24, maxHour + 1);
        minHour = Math.min(minHour, 6);
        maxHour = Math.max(maxHour, 22);

        return {
            minTime: (minHour < 10 ? '0' : '') + minHour + ':00:00',
            maxTime: (maxHour < 10 ? '0' : '') + maxHour + ':00:00'
        };
    }

    function updateCalendarTimeRange(minTime, maxTime) {
        if (!calendarEl) return;

        if (minTime !== currentMinTime || maxTime !== currentMaxTime) {
            currentMinTime = minTime;
            currentMaxTime = maxTime;
            $(calendarEl).fullCalendar('option', 'minTime', minTime);
            $(calendarEl).fullCalendar('option', 'maxTime', maxTime);
        }
    }

    function initCalendar() {
        $(calendarEl).fullCalendar({
            locale: frappe.boot.lang || 'de',
            header: { left: 'prev,next today', center: 'title', right: 'month,agendaWeek,agendaDay' },
            defaultView: 'agendaWeek',
            weekends: showWeekends,
            editable: false,
            selectable: false,
            nowIndicator: true,
            slotDuration: '00:30:00',
            minTime: currentMinTime,
            maxTime: currentMaxTime,
            height: 650,
            contentHeight: 600,
            slotLabelFormat: 'HH:mm',
            timeFormat: 'HH:mm',
            buttonText: { today: 'Heute', month: 'Monat', week: 'Woche', day: 'Tag' },
            eventSources: [
                function(start, end, timezone, callback) { fetchEvents(start, end, callback); },
                function(start, end, timezone, callback) {
                    var bgEvents = [];
                    var current = start.clone();
                    while (current.isBefore(end)) {
                        var dayOfWeek = current.day();
                        if (dayOfWeek >= 1 && dayOfWeek <= 5) {
                            bgEvents.push({
                                start: current.format('YYYY-MM-DD') + 'T08:00:00',
                                end: current.format('YYYY-MM-DD') + 'T17:00:00',
                                rendering: 'background',
                                className: 'core-hours'
                            });
                        }
                        current.add(1, 'day');
                    }
                    callback(bgEvents);
                }
            ],
            eventClick: function(event) {
                var serviceReport = event.extendedProps ? event.extendedProps.service_report : null;
                if (serviceReport) {
                    frappe.set_route('Form', 'Service Report', serviceReport);
                }
            },
            eventRender: function(event, element) {
                if (event.rendering === 'background') return;
                var color = getCustomerColor(event.customer_name || '');
                element.css('background-color', color);
                element.css('border-color', color);
                element.css('cursor', 'pointer');
                element.attr('title', (event.title || '') + ' - Klicken zum Öffnen');
            }
        });
    }

    function fetchEvents(start, end, callback) {
        if (!currentEmployee) { callback([]); return; }
        frappe.call({
            method: 'fieldservice.api.get_service_report_work_times',
            args: {
                start: start.format('YYYY-MM-DD'),
                end: end.format('YYYY-MM-DD'),
                employees: JSON.stringify([currentEmployee.name])
            },
            async: true,
            callback: function(response) {
                var events = response.message || [];
                var timeRange = calculateTimeRange(events);
                updateCalendarTimeRange(timeRange.minTime, timeRange.maxTime);
                callback(events);
            },
            error: function() { callback([]); }
        });
    }

    function setupEventListeners() {
        if (weekendToggleBtn) {
            weekendToggleBtn.addEventListener('click', toggleWeekends);
        }
        if (startDateInput) {
            startDateInput.addEventListener('change', function() {
                if (startDateInput.value && calendarEl) {
                    $(calendarEl).fullCalendar('gotoDate', startDateInput.value);
                }
            });
        }
    }

    function setInitialFilters() {
        var today = new Date();
        var monday = new Date(today);
        var diff = today.getDay() === 0 ? -6 : 1 - today.getDay();
        monday.setDate(today.getDate() + diff);
        var sunday = new Date(monday);
        sunday.setDate(monday.getDate() + 6);
        if (startDateInput) startDateInput.value = monday.toISOString().split('T')[0];
        if (endDateInput) endDateInput.value = sunday.toISOString().split('T')[0];
    }

    function refreshCalendar() {
        if (calendarEl) $(calendarEl).fullCalendar('refetchEvents');
    }

    init();
})();

style:
.sr-calendar-container {
    padding: 15px;
    background: var(--card-bg);
    border-radius: var(--border-radius);
}

.calendar-filters {
    background: var(--subtle-fg);
    padding: 10px 15px;
    border-radius: var(--border-radius);
    margin-bottom: 15px;
}

.filter-row {
    display: flex;
    flex-wrap: wrap;
    gap: 10px;
    align-items: center;
}

.filter-row > label {
    font-weight: 600;
    font-size: 12px;
    color: var(--text-muted);
    margin: 0;
}

.filter-row > span {
    color: var(--text-muted);
}

.filter-row > input {
    width: 140px;
    background-color: var(--card-bg) !important;
    border: 1px solid var(--border-color) !important;
}

.filter-row > .btn {
    background-color: var(--card-bg) !important;
    border: 1px solid var(--border-color) !important;
    margin-left: auto;
}


/* FullCalendar Container Fix */
#work-times-calendar {
    position: relative;
    min-height: 700px;
}

#work-times-calendar .fc {
    font-size: 13px;
}

#work-times-calendar .fc-view-container {
    position: relative;
}

#work-times-calendar .fc-scroller {
    overflow: visible !important;
    height: auto !important;
}

#work-times-calendar .fc-time-grid-container {
    overflow: visible !important;
    height: auto !important;
}

#work-times-calendar .fc-time-grid {
    min-height: 600px;
}

#work-times-calendar .fc-content-skeleton {
    position: relative !important;
    top: 0 !important;
}

#work-times-calendar .fc-toolbar h2 {
    font-size: 1.1rem;
}

#work-times-calendar .fc-event {
    cursor: pointer;
    border: none;
    border-radius: 3px;
    padding: 2px 4px;
    font-size: 11px;
}

#work-times-calendar .fc-time-grid-event {
    margin-right: 1px;
    position: absolute;
}

.event-popup {
    position: fixed;
    top: 0;
    left: 0;
    right: 0;
    bottom: 0;
    background: rgba(0,0,0,0.5);
    display: flex;
    justify-content: center;
    align-items: center;
    z-index: 1060;
}

.event-popup.hidden {
    display: none;
}

.event-popup-content {
    background: var(--card-bg);
    border-radius: var(--border-radius-lg);
    max-width: 500px;
    width: 90%;
    max-height: 80vh;
    overflow-y: auto;
    box-shadow: var(--shadow-lg);
}

.event-popup-header {
    display: flex;
    justify-content: space-between;
    align-items: center;
    padding: 15px;
    border-bottom: 1px solid var(--border-color);
}

.event-popup-header h4 {
    margin: 0;
    font-size: 14px;
    font-weight: 600;
}

.popup-close-btn {
    background: none;
    border: none;
    font-size: 22px;
    cursor: pointer;
    color: var(--text-muted);
    line-height: 1;
    padding: 0;
}

.event-popup-body {
    padding: 15px;
}

.popup-field {
    margin-bottom: 12px;
}

.popup-field label {
    display: block;
    font-size: 11px;
    color: var(--text-muted);
    margin-bottom: 2px;
}

.popup-field span {
    font-size: 13px;
}

.popup-description {
    background: var(--subtle-fg);
    padding: 10px;
    border-radius: var(--border-radius);
    max-height: 120px;
    overflow-y: auto;
    font-size: 12px;
}

.popup-actions {
    margin-top: 15px;
    padding-top: 15px;
    border-top: 1px solid var(--border-color);
}

.service-type-badge {
    display: inline-block;
    padding: 2px 8px;
    border-radius: 10px;
    font-size: 11px;
    font-weight: 500;
    background: var(--subtle-fg);
}
